def handle_data_transform(job_id, payload):
    """Handle data transformation jobs."""
    source = payload.get("source")
    destination = payload.get("destination")
    transform_rules = payload.get("transform_rules", [])
    records = payload.get("records", [])

    logger.info(
        f"Job {job_id}: Transforming {len(records)} records "
        f"from {source} to {destination} with {len(transform_rules)} rules"
    )

    processed_records = []
    for record in records:
        processed_record = apply_transforms(record, transform_rules)
        processed_records.append(processed_record)

    return {
        "status": "completed",
        "records_processed": len(processed_records),
        "destination": destination,
    }


def apply_transforms(record, transform_rules):
    """Apply transformation rules to a record."""
    result = dict(record)
    for rule in transform_rules:
        rule_type = rule.get("type")
        field = rule.get("field")

        if rule_type == "rename" and field in result:
            result[rule["new_name"]] = result.pop(field)
        elif rule_type == "uppercase" and field in result:
            result[field] = str(result[field]).upper()
        elif rule_type == "default" and field not in result:
            result[field] = rule.get("value")
    return result


def handle_aggregation(job_id, payload):
    """Handle data aggregation jobs."""
    dataset = payload.get("dataset", [])
    group_by = payload.get("group_by")
    aggregate_field = payload.get("aggregate_field")
    operation = payload.get("operation", "sum")

    logger.info(
        f"Job {job_id}: Aggregating {len(dataset)} records "
        f"by '{group_by}', operation: {operation}"
    )

    ALLOWED_OPERATIONS = {"sum", "count", "avg", "min", "max"}
    if operation not in ALLOWED_OPERATIONS:
        raise ValueError(f"Unsupported aggregation operation: {operation}")

    groups = {}
    for item in dataset:
        key = item.get(group_by, "unknown")
        if key not in groups:
            groups[key] = []
        if aggregate_field and aggregate_field in item:
            groups[key].append(item[aggregate_field])

    results = {}
    for key, values in groups.items():
        if operation == "sum":
            results[key] = sum(values)
        elif operation == "count":
            results[key] = len(values)
        elif operation == "avg":
            results[key] = sum(values) / len(values) if values else 0
        elif operation == "min":
            results[key] = min(values) if values else None
        elif operation == "max":
            results[key] = max(values) if values else None

    return {"status": "completed", "groups": len(results), "results": results}


